module RefModule(datain, dataout, load, hold, clock);
input [4:0] datain;
input load, hold;
input clock;
output [4:0] dataout;
reg [4:0] input_data;
always @(posedge clock)
begin
    if(load)
       input_data <= datain;
    else if(hold)
       input_data <= input_data;
    else
       input_data <= 5'b0;
end
assign dataout = input_data;
endmodule
